For each order, evaluate insertion cost into every assign's feasible positions via trial insertion with rollback, pick the minimal positive cost increase, otherwise create new assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    nOrders := len(oris)
    if nOrders == 0 || len(dess) != nOrders {
        dispatch.RenewnTotalCost()
        return dispatch
    }

    type BestInsertion struct {
        assignIdx int
        costDelta float64
    }

    for ordIdx := 0; ordIdx < nOrders; ordIdx++ {
        shipID := total_ship + ordIdx
        ori := oris[ordIdx]
        des := dess[ordIdx]

        var best BestInsertion
        best.assignIdx = -1
        best.costDelta = 1e30

        numAssignsToTry := dispatch.AssignsLen
        if numAssignsToTry == 0 {
            numAssignsToTry = 1
        }

        for aIdx := 0; aIdx < numAssignsToTry; aIdx++ {
            if aIdx >= MAXASSIGNS {
                break
            }

            originalCost := dispatch.Assigns[aIdx].Cost
            added := dispatch.Assigns[aIdx].AddShip(shipID, ori, des)
            if added {
                dispatch.Assigns[aIdx].GenRoute()
                newCost := dispatch.Assigns[aIdx].Cost
                costIncrease := newCost - originalCost
                if newCost >= 0 && costIncrease >= 0 {
                    if costIncrease < best.costDelta {
                        best.costDelta = costIncrease
                        best.assignIdx = aIdx
                    }
                }
                dispatch.Assigns[aIdx].RemoveShip(shipID)
                dispatch.Assigns[aIdx].GenRoute()
            }
        }

        if best.assignIdx >= 0 && best.assignIdx < dispatch.AssignsLen {
            dispatch.Assigns[best.assignIdx].AddShip(shipID, ori, des)
            dispatch.Assigns[best.assignIdx].GenRoute()
        } else {
            if dispatch.AssignsLen < MAXASSIGNS {
                idx := dispatch.AssignsLen
                dispatch.Assigns[idx].AddShip(shipID, ori, des)
                dispatch.Assigns[idx].GenRoute()
                if dispatch.Assigns[idx].Cost >= 0 {
                    dispatch.AssignsLen++
                } else {
                    dispatch.Assigns[idx].RemoveShip(shipID)
                    dispatch.Assigns[idx].GenRoute()
                }
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

